1	// CLI: reads JSON scenario from stdin, writes {results:[...]} to stdout.
2	import { readFileSync } from "node:fs";
3	import { quote, claim } from "./claim-office.js";
4	
5	const scenario = JSON.parse(readFileSync(0, "utf-8"));
6	const yearsWithMHPCO = scenario.customer.yearsWithMHPCO;
7	
8	const KNOWN_ITEM_TYPES = new Set([
9	  "sword",
10	  "amulet",
11	  "staff",
12	  "potion",
13	  "rune",
14	  "moonstone",
15	]);
16	
17	function assertKnownItemTypes(items: { type: string }[]): void {
18	  for (const item of items) {
19	    if (!KNOWN_ITEM_TYPES.has(item.type)) {
20	      process.stderr.write(`Unknown item type: ${item.type}\n`);
21	      process.exit(1);
22	    }
23	  }
24	}
25	
26	const results = [];
27	const policies = [];
28	
29	for (const step of scenario.steps) {
30	  if (step.op === "quote") {
31	    assertKnownItemTypes(step.items);
32	    const { premium } = quote({
33	      items: step.items,
34	      yearsWithMHPCO,
35	      firstInsurance: true,
36	      followUp: policies.length > 0,
37	    });
38	    policies.push(step);
39	    results.push({ premium });
40	  } else if (step.op === "claim") {
41	    const items = policies[step.policy].items;
42	    const insuredTypes = new Set(items.map((item: { type: string }) => item.type));
43	    for (const damage of step.incident.damages) {
44	      if (!insuredTypes.has(damage.itemType)) {
45	        process.stderr.write(`Damaged item not in policy: ${damage.itemType}\n`);
46	        process.exit(1);
47	      }
48	    }
49	    const { payout, remainingCap } = claim(items, step.incident);
50	    results.push({ payout, remainingCap });
51	  }
52	}
53	
54	process.stdout.write(JSON.stringify({ results }));
55	process.exit(0);
